// ============================================================
// KGen VEO 3.1 — Prepare Generate Request
// Maps frontend payload → kie.ai API format
// ============================================================

const body = $input.first().json.body;

// Required
if (!body.prompt) throw new Error('prompt is required');

// Build payload
const payload = {
  prompt: body.prompt,
  model: body.model || 'veo3_fast',
  aspect_ratio: body.aspect_ratio || '16:9',
  enableTranslation: body.enableTranslation !== false,
  enableFallback: false,
};

// Generation type
if (body.generationType) {
  payload.generationType = body.generationType;
}

// Seed
if (body.seeds && body.seeds >= 10000 && body.seeds <= 99999) {
  payload.seeds = body.seeds;
}

// Watermark (optional)
if (body.watermark) {
  payload.watermark = body.watermark;
}

// Image URLs from frontend dataUrls
// Frontend sends base64 dataUrls → we need public URLs
// Strategy: if imageDataUrls provided, extract them
if (body.imageDataUrls && body.imageDataUrls.length > 0) {
  // For now, pass as-is — production should upload to CDN first
  // kie.ai requires public accessible URLs
  payload.imageUrls = body.imageDataUrls;
}

// For REFERENCE_2_VIDEO, force veo3_fast
if (payload.generationType === 'REFERENCE_2_VIDEO') {
  payload.model = 'veo3_fast';
}

// User API key override
const userApiKey = body.userApiKey || '';

return [{
  json: {
    payload,
    userApiKey,
    originalBody: body,
  }
}];

// Handle response from kie.ai
const result = $input.first().json;

if (result.code !== 200) {
  return [{
    json: {
      success: false,
      code: result.code,
      msg: result.msg || 'Lỗi từ kie.ai API',
      data: null,
    }
  }];
}

return [{
  json: {
    success: true,
    code: 200,
    msg: 'success',
    data: {
      taskId: result.data?.taskId,
    }
  }
}];

// Extract taskId from status check request
const body = $input.first().json.body;
const taskId = body.taskId;

if (!taskId) throw new Error('taskId is required');

return [{ json: { taskId } }];

// Process status response
const result = $input.first().json;

// Forward the raw response from kie.ai
return [{
  json: {
    code: result.code,
    msg: result.msg,
    data: result.data,
    status: result.data?.info ? 'COMPLETED' : 'PROCESSING',
  }
}];
